  ('social-worker-moex-05960', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關「在消滅資本主義所帶來的不平等上，政府所採行的為普及式或制度式福利；透過所得重分配方式， 減少社會日漸產生的對立，促成社會的和諧」，此為何種意識形態之主張？', '["新右派", "社群主義", "新自由主義", "社會民主觀點"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
