  ('social-worker-moex-05962', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '學者Howard M. Leichter主張影響社會政策制訂之因素有情境、結構、文化與環境因素，下列敘述何者為 結構因素？', '["外部體系對體系內進行決策事件造成影響", "其影響因素較具有持續性，如政治制度", "指一種偶發、非永久或特殊性的事件所造成的影響", "指一個社群中的部分或整體社群所持有的價值觀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05963', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關立法院審議法律程序的敘述，何者錯誤？', '["立法委員不能一人自行提案，其提案須經一定數額委員連署乃得提案", "法案審議的優先順序由立法院程序委員會決定", "法律經過一讀會後一定會進入付委審查，以利與行政部門溝通", "三讀會中，除發現議案內容有相互抵觸或與憲法及其他法律抵觸外，只得為文字之修正"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05964', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據1991年聯合國老人綱領之主張，共計有五項主題作為國際老人福利應追求的共同目標，該主題不包 括下列何者？', '["參與", "照顧", "自我實現", "權利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05965', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關全民健康保險法之被保險人區分為六類，下列何者為第一類保險人？', '["公、民營事業、機關之受僱者", "低收入戶成員", "農會及水利會會員", "服替代役期間之役齡男子"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05966', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '在社會福利發展的觀點中，主張外部因素的示範效果才是社會福利形成的主要因素，不同社經發展程度 國家間的學習，此種擴散作用稱為：', '["空間擴散", "平移擴散", "垂直擴散", "層級擴散"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05967', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '政策的形成乃是依據過去的經驗，經由社會變遷的過程，而獲致共同一致的政策，此種政策制定的模型稱為：', '["理性模型", "漸進決策模型", "菁英決策模型", "團體決策模型"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05968', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會救助法之敘述，下列何者正確？', '["直轄市、縣（市）主管機關應自受理申請生活扶助之日起五日內，派員調查申請人家庭環境、經濟狀 況等項目", "低收入戶之生活扶助以實物給付為原則", "中低收入戶參加全民健康保險之保險費，由中央主管機關編列預算全額補助", "主管機關應每四年辦理低收入戶及中低收入戶生活狀況調查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05969', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會救助法中規定具有工作能力未就業者，依基本工資核算，但下列何種情形得不予列計？', '["經私立就業服務機構認定失業者", "五十五歲以上經公立就業服務機構媒介五次以上未媒合成功者", "參加政府主辦或委辦全日制職業訓練，其失業或參加職業訓練期間得不計算工作收入", "最近一年度之財稅資料查無工作收入，且未能提出薪資證明者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 18, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
